def maxCoins(nums: list[int]) -> int:
    n = len(nums)

    points = [1] + nums + [1]
    n_padded = len(points)

    dp = [[0] * n_padded for _ in range(n_padded)]

    for length in range(2, n_padded): 
        for i in range(n_padded - length):
            j = i + length

            for k in range(i + 1, j):
                current_coins = dp[i][k] + dp[k][j] + points[i] * points[k] * points[j]
                dp[i][j] = max(dp[i][j], current_coins)

    return dp[0][n_padded - 1]
